import { apiClient, unwrap } from '@linm-soft/common-components';
import type { BffResponse } from '@linm-soft/common-components';
import type { PaginatedResult } from './models';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

/** Unwrap BE `PaginatedResult` — SearchInput / list parity. */
export async function fetchPaginated<T>(
  path: string,
  params?: Record<string, string | number | boolean | undefined>,
): Promise<{ items: T[]; totalCount: number; page: number; pageSize: number }> {
  const qs = params ? buildQs(params) : '';
  const url = qs ? `${path}?${qs}` : path;
  const res = await apiClient.get<BffResponse<PaginatedResult<T>>>(url);
  const data = unwrap(res);
  return {
    items: data?.items ?? [],
    totalCount: data?.totalCount ?? 0,
    page: data?.page ?? 1,
    pageSize: data?.pageSize ?? 20,
  };
}
